"use client";

import { useEffect, useState } from "react";

import {
  Price,
  type PriceType,
  PriceValue,
} from "@/components/shadcnblocks/price";
import { Rating } from "@/components/shadcnblocks/rating";
import { Card, CardContent, CardDescription } from "@/components/ui/card";
import type { CarouselApi } from "@/components/ui/carousel";
import {
  Carousel,
  CarouselContent,
  CarouselItem,
  CarouselNext,
  CarouselPrevious,
} from "@/components/ui/carousel";
import { cn } from "@/lib/utils";

type Product = {
  name: string;
  image: string;
  price: PriceType;
  link: string;
};

type ReviewType = {
  image: string;
  rate: number;
  comment: string;
  author: string;
  product: Product;
};

interface Reviews6Props {
  title: string;
  overline?: string;
  reviews: ReviewType[];
  className?: string;
}

type ReviewCardProps = ReviewType;
type ProductCardProps = Product;

const REVIEWS: ReviewType[] = [
  {
    image:
      "https://deifkwefumgah.cloudfront.net/shadcnblocks/block/ecommerce/electronics/Serene-Listening-2.png",
    rate: 5,
    comment:
      '"These headphones completely changed my daily routine. The sound is rich, the fit is perfect, and the noise isolation is impressive. I genuinely enjoy using them."',
    author: "Evan R.",
    product: {
      name: "AeroTone Wireless Headphones",
      image:
        "https://deifkwefumgah.cloudfront.net/shadcnblocks/block/ecommerce/electronics/Modern-White-Headphones-1.png",
      price: {
        regular: 566.0,
        currency: "USD",
      },
      link: "#",
    },
  },
  {
    image:
      "https://deifkwefumgah.cloudfront.net/shadcnblocks/block/ecommerce/electronics/Woman-Smiling-Indoors-2.png",
    rate: 5,
    comment:
      '"This smartphone feels like a real upgrade. The camera is sharp, the screen is gorgeous, and the performance is flawless. I absolutely love using it daily."',
    author: "Sofia L.",
    product: {
      name: "LumaEdge Pro Smartphone",
      image:
        "https://deifkwefumgah.cloudfront.net/shadcnblocks/block/ecommerce/electronics/Sleek-Smartphone-Close-Up-1.png",
      price: {
        regular: 1566.0,
        currency: "USD",
      },
      link: "#",
    },
  },
];

const Reviews6 = ({
  reviews = REVIEWS,
  title = "+10000 Happy Customers",
  overline = "What Our Customers Say",
  className,
}: Reviews6Props) => {
  const [api, setApi] = useState<CarouselApi>();
  const [current, setCurrent] = useState(0);
  const [scrollSnaps, setScrollSnaps] = useState<number[]>([]);

  const onButtonClick = (index: number) => {
    if (!api) return;
    api?.scrollTo(index);
  };

  useEffect(() => {
    if (!api) return;

    const updateCurrent = (api: CarouselApi) => {
      setCurrent(api?.selectedScrollSnap() ?? 0);
    };

    const updateScrollSnaps = (api: CarouselApi) => {
      setScrollSnaps(api?.scrollSnapList() ?? []);
    };

    updateCurrent(api);
    updateScrollSnaps(api);

    api
      .on("reInit", updateCurrent)
      .on("select", updateCurrent)
      .on("resize", updateScrollSnaps);

    return () => {
      api
        .off("reInit", updateCurrent)
        .off("select", updateCurrent)
        .off("resize", updateScrollSnaps);
    };
  }, [api]);

  return (
    <section className={cn("bg-primary py-32", className)}>
      <div className="container space-y-7 lg:space-y-10">
        <div className="space-y-3 text-center">
          {overline && (
            <p className="leading-normal text-primary-foreground">{overline}</p>
          )}
          <h2 className="text-4xl font-bold text-primary-foreground lg:text-6xl">
            {title}
          </h2>
        </div>
        <div className="space-y-5">
          <Carousel setApi={setApi} className="group">
            <CarouselContent>
              {reviews.map((review, index) => (
                <CarouselItem key={index}>
                  <ReviewCard {...review} />
                </CarouselItem>
              ))}
            </CarouselContent>
            <div className="opacity-0 transition-opacity group-hover:opacity-100">
              <CarouselPrevious className="left-5" />
              <CarouselNext className="right-5" />
            </div>
          </Carousel>
          <div className="flex items-center justify-center gap-2">
            {scrollSnaps.map((_, index) => (
              <button
                data-state={current === index ? "active" : "inactive"}
                className="group flex size-5"
                key={index}
                onClick={() => {
                  onButtonClick(index);
                }}
              >
                <span className="m-auto block size-2 rounded-full bg-primary-foreground/50 group-data-[state=active]:bg-primary-foreground"></span>
              </button>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
};

const ReviewCard = ({
  image,
  product,
  rate,
  comment,
  author,
}: ReviewCardProps) => {
  return (
    <Card className="h-full max-h-fit min-h-132.5 overflow-hidden border-none p-0">
      <CardContent className="h-full p-0 lg:grid lg:grid-cols-2">
        <div className="relative max-md:flex max-md:flex-col">
          <div className="relative size-full overflow-hidden max-lg:aspect-[1.4]">
            <div className="absolute inset-0">
              <img
                src={image}
                alt={product.name}
                className="block size-full object-cover object-center"
              />
            </div>
          </div>
          <div className="md:absolute md:bottom-4 md:left-4">
            <ProductCard {...product} />
          </div>
        </div>
        <div className="flex p-8 lg:px-20 lg:py-12">
          <div className="m-auto w-full space-y-4">
            <div className="w-fit max-lg:mx-auto">
              <Rating
                rate={rate}
                className="[&>svg]:fill-yellow-500 [&>svg]:stroke-yellow-500"
              />
            </div>
            <CardDescription className="text-xl leading-normal text-foreground max-lg:text-center lg:text-2xl">
              {comment}
            </CardDescription>
            <p className="text-sm font-semibold max-lg:text-center">
              - {author}
            </p>
          </div>
        </div>
      </CardContent>
    </Card>
  );
};

const ProductCard = ({ image, name, price }: ProductCardProps) => {
  const { regular, sale, currency } = price;

  return (
    <div className="min-h-31 border bg-background p-2 pr-8 md:max-w-100 md:rounded-xl md:shadow-xl">
      <div className="flex items-center gap-4">
        <div className="shrink-0 basis-28">
          <div className="size-28 overflow-hidden rounded-lg">
            <img
              src={image}
              alt={name}
              className="block size-full object-cover object-center"
            />
          </div>
        </div>
        <div className="space-y-1">
          <h3 className="text-base">{name}</h3>
          <Price className="text-sm font-semibold" onSale={!!sale}>
            <PriceValue variant="sale" price={sale} currency={currency} />
            <PriceValue variant="regular" price={regular} currency={currency} />
          </Price>
        </div>
      </div>
    </div>
  );
};

export { Reviews6 };

"use client";

import type { ReactNode } from "react";
import { createContext, useContext } from "react";

import { cn } from "@/lib/utils";

const PriceContext = createContext<{ onSale?: boolean }>({ onSale: false });
export const usePriceContext = () => useContext(PriceContext);

interface PriceProps {
  className?: string;
  children: ReactNode;
  onSale?: boolean;
}

interface PriceValueProps {
  price?: number;
  currency?: string;
  variant?: "regular" | "sale";
  className?: string;
}

export type PriceType = {
  currency?: string;
  regular: number;
  sale?: number;
};

const formatterCache = new Map<string, Intl.NumberFormat>();

function formatCurrency(value: number, currency = "USD", locale = "en-US") {
  const key = `${locale}-${currency}`;
  if (!formatterCache.has(key)) {
    formatterCache.set(
      key,
      new Intl.NumberFormat(locale, { style: "currency", currency }),
    );
  }
  return formatterCache.get(key)!.format(value);
}

const Price = ({ className, children, onSale }: PriceProps) => {
  return (
    <PriceContext.Provider value={{ onSale }}>
      <div className={cn("flex flex-wrap items-center gap-x-2", className)}>
        {children}
      </div>
    </PriceContext.Provider>
  );
};

const PriceValue = ({
  price,
  currency = "USD",
  variant = "regular",
  className,
}: PriceValueProps) => {
  const { onSale } = usePriceContext();

  if (price == null) return null;

  return (
    <span
      className={cn(
        "leading-tight",
        variant === "regular"
          ? onSale
            ? "text-muted-foreground line-through"
            : "text-foreground"
          : "text-foreground",
        className,
      )}
    >
      {formatCurrency(price, currency)}
    </span>
  );
};

export { Price, PriceValue };

'use client';

import { Star, StarHalf } from 'lucide-react';

import { cn } from '@/lib/utils';

const MAX_STARS = 5;

interface RatingProps {
  rate: number;
  className?: string;
  showScore?: boolean;
  description?: string;
}

const Rating = ({ rate, className, showScore, description }: RatingProps) => {
  if (!rate) return;

  const renderStars = () => {
    const fullStars = Math.floor(rate);
    const hasHalfStar = rate % 1 >= 0.5;
    const emptyStars = MAX_STARS - fullStars - (hasHalfStar ? 1 : 0);

    const stars = [];

    for (let i = 0; i < fullStars; i++) {
      stars.push(
        <Star
          key={`rating-star-full-${i}`}
          className="fill-foreground stroke-foreground"
        />,
      );
    }

    if (hasHalfStar) {
      stars.push(
        <div key="rating-half-star" className="relative">
          <StarHalf className="absolute top-0 right-0 fill-foreground stroke-foreground" />
          <StarHalf className="absolute top-0 left-0 -scale-x-100 fill-foreground/15 stroke-foreground/15" />
        </div>,
      );
    }

    for (let i = 0; i < emptyStars; i++) {
      stars.push(
        <Star
          key={`rating-star-empty-${i}`}
          className="fill-foreground/15 stroke-foreground/15"
        />,
      );
    }

    return stars;
  };

  // If only score is shown (no description), use horizontal layout
  if (showScore && !description) {
    return (
      <div
        className={cn(
          'flex items-center gap-2 [&_svg]:size-5 [&>div]:size-5',
          className,
        )}
      >
        {renderStars()}
        <span className="text-sm font-semibold">{rate.toFixed(1)}</span>
      </div>
    );
  }

  // If description is provided, use vertical layout
  if (description) {
    return (
      <div className={cn('flex flex-col gap-1', className)}>
        <div className="flex items-center gap-2 [&_svg]:size-5 [&>div]:size-5">
          {renderStars()}
          {showScore && (
            <span className="text-sm font-semibold">{rate.toFixed(1)}</span>
          )}
        </div>
        <p className="text-sm text-muted-foreground">{description}</p>
      </div>
    );
  }

  // Default: just stars
  return (
    <div
      className={cn(
        'flex items-center gap-1 [&_svg]:size-5 [&>div]:size-5',
        className,
      )}
    >
      {renderStars()}
    </div>
  );
};

export { Rating };
